import { DEBUG } from '../../config';
import { animate } from '../../util/animation';
import {
  IS_ANDROID, IS_IOS, IS_SAFARI,
} from '../../util/browser/windowEnvironment';
import cycleRestrict from '../../util/cycleRestrict';
import Deferred from '../../util/Deferred';
import generateUniqueId from '../../util/generateUniqueId';
import { MAX_WORKERS, requestMediaWorker } from '../../util/launchMediaWorkers';
import { requestMeasure, requestMutation } from '../fasterdom/fasterdom';

interface Params {
  size: number;
  noLoop?: boolean;
  quality?: number;
  isLowPriority?: boolean;
  coords?: { x: number; y: number };
}

const WAITING = Symbol('WAITING');
// The frame was handed to a `bitmaprenderer` canvas (which consumed it); re-requested on the next loop pass
const CONSUMED = Symbol('CONSUMED');
type Frame =
  undefined
  | typeof WAITING
  | typeof CONSUMED
  | ImageBitmap;

function isBitmap(frame: Frame): frame is ImageBitmap {
  return Boolean(frame) && frame !== WAITING && frame !== CONSUMED;
}

type FrameCallback = (index: number) => void;

type ViewInfo = {
  canvas: HTMLCanvasElement;
  ctx?: CanvasRenderingContext2D;
  bitmapCtx?: ImageBitmapRenderingContext;
  isLoaded?: boolean;
  isPaused?: boolean;
  isSharedCanvas?: boolean;
  coords?: Params['coords'];
  onLoad?: NoneToVoidFunction;
  onFrame?: FrameCallback;
};

const HIGH_PRIORITY_QUALITY = (IS_ANDROID || IS_IOS) ? 0.75 : 1;
const LOW_PRIORITY_QUALITY = IS_ANDROID ? 0.5 : 0.75;
const LOW_PRIORITY_QUALITY_SIZE_THRESHOLD = 24;
const MAX_RENDER_DPR = 1.5;
const HIGH_PRIORITY_CACHE_MODULO = IS_SAFARI ? 2 : 4;
const LOW_PRIORITY_CACHE_MODULO = 0;
// Loops larger than this, or arriving when the global budget is exhausted, only keep a sliding window of frames.
// Both `Infinity` restores the unbounded `cacheModulo`-only policy
const MAX_LOOP_CACHE_BYTES = 2 * 1024 * 1024;
const FRAME_CACHE_GLOBAL_BUDGET_BYTES = 32 * 1024 * 1024;
const BOUNDED_CACHE_WINDOW = 5;
const CANVAS_CLASS = 'rlottie-canvas';

const instancesByRenderId = new Map<string, RLottie>();

const frameStats = { count: 0, bytes: 0 };

function countCachedFrame(frame: ImageBitmap) {
  frameStats.count++;
  frameStats.bytes += frame.width * frame.height * 4;
}

function discountCachedFrame(frame: ImageBitmap) {
  frameStats.count--;
  frameStats.bytes -= frame.width * frame.height * 4;
}

if (DEBUG && typeof window !== 'undefined') {
  (window as any).__rlottieStats = () => ({
    instances: instancesByRenderId.size,
    cachedFrames: frameStats.count,
    cachedFrameBytes: frameStats.bytes,
  });
}

const PENDING_CANVAS_RESIZES = new WeakMap<HTMLCanvasElement, Promise<void>>();

let lastWorkerIndex = -1;

class RLottie {
  // Config

  private views = new Map<string, ViewInfo>();

  private hasBitmapRendererView = false;

  private imgSize!: number;

  private msPerFrame = 1000 / 60;

  private reduceFactor = 1;

  private cacheModulo!: number;

  private isCacheBounded?: boolean;

  private workerIndex!: number;

  private frames: Frame[] = [];

  private framesCount?: number;

  // State

  private isAnimating = false;

  private isWaiting = true;

  private isEnded = false;

  private isDestroyed = false;

  private isRendererInited = false;

  private approxFrameIndex = 0;

  private prevFrameIndex = -1;

  private stopFrameIndex? = 0;

  private speed = 1;

  private direction: 1 | -1 = 1;

  private lastRenderAt?: number;

  private requestedSeekToEnd = false;

  static init(...args: ConstructorParameters<typeof RLottie>) {
    const [
      , canvas,
      renderId,
      params,
      viewId = generateUniqueId(),
      ,
      onLoad,
      ,
      ,
      onFrame,
    ] = args;
    let instance = instancesByRenderId.get(renderId);

    if (!instance) {
      instance = new RLottie(...args);
      instancesByRenderId.set(renderId, instance);
    } else {
      instance.addView(viewId, canvas, onLoad, onFrame, params?.coords);
    }

    return instance;
  }

  constructor(
    private tgsUrl: string,
    container: HTMLDivElement | HTMLCanvasElement,
    private renderId: string,
    private params: Params,
    viewId: string = generateUniqueId(),
    private customColor?: [number, number, number],
    onLoad?: NoneToVoidFunction | undefined,
    private onEnded?: (isDestroyed?: boolean) => void,
    private onLoop?: () => void,
    onFrame?: FrameCallback,
  ) {
    this.addView(viewId, container, onLoad, onFrame, params.coords);
    this.initConfig();
    this.initRenderer();
  }

  public removeView(viewId: string) {
    const {
      canvas, ctx, bitmapCtx, isSharedCanvas, coords,
    } = this.views.get(viewId)!;

    if (isSharedCanvas) {
      ctx!.clearRect(coords!.x, coords!.y, this.imgSize, this.imgSize);
    } else {
      canvas.remove();
    }

    if (bitmapCtx) {
      this.hasBitmapRendererView = false;
    }

    this.views.delete(viewId);

    if (!this.views.size) {
      this.destroy();
    }
  }

  isPlaying() {
    return this.isAnimating || this.isWaiting;
  }

  play(forceRestart = false, viewId?: string) {
    if (viewId) {
      this.views.get(viewId)!.isPaused = false;
    }

    if (this.isEnded && forceRestart) {
      this.approxFrameIndex = Math.floor(0);
    }

    this.stopFrameIndex = undefined;
    this.direction = 1;
    this.doPlay();
  }

  pause(viewId?: string) {
    this.lastRenderAt = undefined;

    if (viewId) {
      this.views.get(viewId)!.isPaused = true;

      const areAllContainersPaused = Array.from(this.views.values()).every(({ isPaused }) => isPaused);
      if (!areAllContainersPaused) {
        return;
      }
    }

    if (this.isWaiting) {
      this.stopFrameIndex = this.approxFrameIndex;
    } else {
      this.isAnimating = false;
    }

    this.frames = this.frames.map((frame, i) => {
      if (i === this.prevFrameIndex) {
        return frame;
      } else {
        if (isBitmap(frame)) {
          discountCachedFrame(frame);
          frame.close();
        }

        return undefined;
      }
    });
  }

  playSegment([startFrameIndex, stopFrameIndex]: [number, number], forceRestart = false, viewId?: string) {
    if (viewId) {
      this.views.get(viewId)!.isPaused = false;
    }

    const frameIndex = Math.round(this.approxFrameIndex);
    this.stopFrameIndex = Math.floor(stopFrameIndex / this.reduceFactor);
    if (frameIndex !== stopFrameIndex || forceRestart) {
      this.approxFrameIndex = Math.floor(startFrameIndex / this.reduceFactor);
    }
    this.direction = startFrameIndex < stopFrameIndex ? 1 : -1;

    this.doPlay();
  }

  seekToEnd() {
    this.requestedSeekToEnd = true;
    this.doPlay();
  }

  setSpeed(speed: number) {
    this.speed = speed;
  }

  setNoLoop(noLoop?: boolean) {
    this.params.noLoop = noLoop;
  }

  async setSharedCanvasCoords(viewId: string, newCoords: Params['coords']) {
    const containerInfo = this.views.get(viewId)!;
    const {
      canvas, ctx,
    } = containerInfo;

    const isCanvasDirty = !canvas.dataset.isJustCleaned || canvas.dataset.isJustCleaned === 'false';

    if (!isCanvasDirty) {
      await PENDING_CANVAS_RESIZES.get(canvas);
    }

    let [canvasWidth, canvasHeight] = [canvas.width, canvas.height];

    if (isCanvasDirty) {
      const sizeFactor = this.calcSizeFactor();
      ([canvasWidth, canvasHeight] = ensureCanvasSize(canvas, sizeFactor));
      ctx!.clearRect(0, 0, canvasWidth, canvasHeight);
      canvas.dataset.isJustCleaned = 'true';
      requestMeasure(() => {
        canvas.dataset.isJustCleaned = 'false';
      });
    }

    containerInfo.coords = {
      x: Math.round((newCoords?.x || 0) * canvasWidth),
      y: Math.round((newCoords?.y || 0) * canvasHeight),
    };

    const frame = this.getFrame(this.prevFrameIndex) || this.getFrame(Math.round(this.approxFrameIndex));

    if (isBitmap(frame)) {
      ctx!.drawImage(frame, containerInfo.coords.x, containerInfo.coords.y);
    }
  }

  private addView(
    viewId: string,
    container: HTMLDivElement | HTMLCanvasElement,
    onLoad?: NoneToVoidFunction,
    onFrame?: FrameCallback,
    coords?: Params['coords'],
  ) {
    const sizeFactor = this.calcSizeFactor();

    let imgSize: number;

    if (container instanceof HTMLDivElement) {
      if (!(container.parentNode instanceof HTMLElement)) {
        throw new Error('[RLottie] Container is not mounted');
      }

      const { size } = this.params;

      imgSize = Math.round(size * sizeFactor);

      if (!this.imgSize) {
        this.imgSize = imgSize;
      }

      requestMutation(() => {
        const canvas = document.createElement('canvas');

        canvas.classList.add(CANVAS_CLASS);

        canvas.style.width = `${size}px`;
        canvas.style.height = `${size}px`;

        canvas.width = imgSize;
        canvas.height = imgSize;

        container.appendChild(canvas);

        // One view per instance hands frames to the compositor directly — no 2D backing store and no
        // main-thread raster. `transferFromImageBitmap` consumes the bitmap, so any further views of the
        // same animation keep the `drawImage` path and are drawn before the transfer
        const bitmapCtx = (!this.hasBitmapRendererView && canvas.getContext('bitmaprenderer')) || undefined;
        if (bitmapCtx) {
          this.hasBitmapRendererView = true;
          this.views.set(viewId, {
            canvas, bitmapCtx, onLoad, onFrame,
          });
        } else {
          this.views.set(viewId, {
            canvas, ctx: canvas.getContext('2d')!, onLoad, onFrame,
          });
        }
      });
    } else {
      if (!container.isConnected) {
        throw new Error('[RLottie] Shared canvas is not mounted');
      }

      const canvas = container;
      const ctx = canvas.getContext('2d')!;

      imgSize = Math.round(this.params.size * sizeFactor);

      if (!this.imgSize) {
        this.imgSize = imgSize;
      }

      const [canvasWidth, canvasHeight] = ensureCanvasSize(canvas, sizeFactor);

      this.views.set(viewId, {
        canvas,
        ctx,
        isSharedCanvas: true,
        coords: {
          x: Math.round(coords!.x * canvasWidth),
          y: Math.round(coords!.y * canvasHeight),
        },
        onLoad,
      });
    }

    if (this.isRendererInited) {
      this.doPlay();
    }
  }

  private calcSizeFactor() {
    const {
      size,
      isLowPriority,
      // Reduced quality only looks acceptable on big enough images
      quality = isLowPriority && (!size || size > LOW_PRIORITY_QUALITY_SIZE_THRESHOLD)
        ? LOW_PRIORITY_QUALITY : HIGH_PRIORITY_QUALITY,
    } = this.params;

    // Reduced quality only looks acceptable on high DPR screens.
    // The DPR itself is capped: on a 2x screen frames render slightly softer
    // in exchange for ~2x fewer pixels per frame (memory and render CPU)
    return Math.max(Math.min(window.devicePixelRatio, MAX_RENDER_DPR) * quality, 1);
  }

  private destroy() {
    this.isDestroyed = true;
    this.pause();
    this.clearCache();
    this.destroyRenderer();

    instancesByRenderId.delete(this.renderId);
  }

  private clearCache() {
    this.frames.forEach((frame) => {
      if (isBitmap(frame)) {
        discountCachedFrame(frame);
        frame.close();
      }
    });

    this.frames = [];
  }

  private initConfig() {
    const { isLowPriority } = this.params;

    this.cacheModulo = isLowPriority ? LOW_PRIORITY_CACHE_MODULO : HIGH_PRIORITY_CACHE_MODULO;
  }

  setColor(newColor: [number, number, number] | undefined) {
    this.customColor = newColor;
  }

  private initRenderer() {
    this.workerIndex = cycleRestrict(MAX_WORKERS, ++lastWorkerIndex);

    requestMediaWorker({
      name: 'rlottie:init',
      args: [
        this.renderId,
        this.tgsUrl,
        this.imgSize,
        this.params.isLowPriority || false,
        this.customColor,
        this.onRendererInit.bind(this),
      ],
    }, this.workerIndex);
  }

  private destroyRenderer() {
    requestMediaWorker({
      name: 'rlottie:destroy',
      args: [this.renderId],
    }, this.workerIndex);
  }

  private onRendererInit(reduceFactor: number, msPerFrame: number, framesCount: number) {
    this.isRendererInited = true;
    this.reduceFactor = reduceFactor;
    this.msPerFrame = msPerFrame;
    this.framesCount = framesCount;
    this.updateCacheMode();

    if (this.isWaiting) {
      this.doPlay();
    }
  }

  changeData(tgsUrl: string) {
    this.pause();
    this.tgsUrl = tgsUrl;
    this.initConfig();

    requestMediaWorker({
      name: 'rlottie:changeData',
      args: [
        this.renderId,
        this.tgsUrl,
        this.params.isLowPriority || false,
        this.onChangeData.bind(this),
      ],
    }, this.workerIndex);
  }

  private onChangeData(reduceFactor: number, msPerFrame: number, framesCount: number) {
    this.reduceFactor = reduceFactor;
    this.msPerFrame = msPerFrame;
    this.framesCount = framesCount;
    this.updateCacheMode();
    this.isWaiting = false;
    this.isAnimating = false;

    this.doPlay();
  }

  private updateCacheMode() {
    const loopBytes = this.imgSize * this.imgSize * 4 * this.framesCount!;

    this.isCacheBounded = loopBytes > MAX_LOOP_CACHE_BYTES
      || frameStats.bytes + loopBytes > FRAME_CACHE_GLOBAL_BUDGET_BYTES;
  }

  private doPlay() {
    if (!this.framesCount) {
      return;
    }

    if (this.isDestroyed) {
      return;
    }

    if (this.requestedSeekToEnd) {
      this.approxFrameIndex = this.framesCount - 1;
      this.stopFrameIndex = undefined;
      this.requestedSeekToEnd = false;
    }

    if (this.isAnimating) {
      return;
    }

    if (!this.isWaiting) {
      this.lastRenderAt = undefined;
    }

    this.isEnded = false;
    this.isAnimating = true;
    this.isWaiting = false;

    animate(() => {
      if (this.isDestroyed) {
        return false;
      }

      // Paused from outside
      if (!this.isAnimating) {
        const areAllLoaded = Array.from(this.views.values()).every(({ isLoaded }) => isLoaded);
        if (areAllLoaded) {
          return false;
        }
      }

      const frameIndex = Math.round(this.approxFrameIndex);
      const frame = this.getFrame(frameIndex);
      const isConsumedStale = frame === CONSUMED && frameIndex !== this.prevFrameIndex;
      if (!frame || frame === WAITING || isConsumedStale) {
        if (!frame || isConsumedStale) {
          this.requestFrame(frameIndex);
        }

        this.isAnimating = false;
        this.isWaiting = true;
        return false;
      }

      if (this.isCacheBounded) {
        this.trimFrameCache(frameIndex);
      } else if (this.cacheModulo && frameIndex % this.cacheModulo === 0) {
        this.cleanupPrevFrame(frameIndex);
      }

      if (frameIndex !== this.prevFrameIndex && frame !== CONSUMED) {
        // The transfer view is drawn last: `transferFromImageBitmap` detaches the bitmap
        let transferView: ViewInfo | undefined;

        this.views.forEach((containerData) => {
          const {
            ctx, bitmapCtx, isLoaded, isPaused, coords: { x, y } = {}, onLoad, onFrame,
          } = containerData;

          if (isLoaded && isPaused) {
            return;
          }

          if (bitmapCtx) {
            transferView = containerData;
            return;
          }

          ctx!.clearRect(x || 0, y || 0, this.imgSize, this.imgSize);
          ctx!.drawImage(frame, x || 0, y || 0);
          onFrame?.(frameIndex);

          if (!isLoaded) {
            containerData.isLoaded = true;
            onLoad?.();
          }
        });

        if (transferView) {
          // Discount first: the transfer detaches the bitmap and zeroes its dimensions
          discountCachedFrame(frame);
          transferView.bitmapCtx!.transferFromImageBitmap(frame);
          this.frames[frameIndex] = CONSUMED;
          transferView.onFrame?.(frameIndex);

          if (!transferView.isLoaded) {
            transferView.isLoaded = true;
            transferView.onLoad?.();
          }
        }

        this.prevFrameIndex = frameIndex;
      }

      const now = Date.now();
      const currentSpeed = this.lastRenderAt ? this.msPerFrame / (now - this.lastRenderAt) : 1;
      const delta = (this.direction * this.speed) / currentSpeed;
      const expectedNextFrameIndex = Math.round(this.approxFrameIndex + delta);

      this.lastRenderAt = now;

      // Forward animation finished
      if (delta > 0 && (frameIndex === this.framesCount! - 1 || expectedNextFrameIndex > this.framesCount! - 1)) {
        if (this.params.noLoop) {
          this.isAnimating = false;
          this.isEnded = true;
          this.onEnded?.();
          return false;
        }
        this.onLoop?.();

        this.approxFrameIndex = 0;

        // Backward animation finished
      } else if (delta < 0 && (frameIndex === 0 || expectedNextFrameIndex < 0)) {
        if (this.params.noLoop) {
          this.isAnimating = false;
          this.isEnded = true;
          this.onEnded?.();
          return false;
        }
        this.onLoop?.();

        this.approxFrameIndex = this.framesCount! - 1;

        // Stop frame reached
      } else if (
        this.stopFrameIndex !== undefined
        && (frameIndex === this.stopFrameIndex
          || (
            (delta > 0 && expectedNextFrameIndex > this.stopFrameIndex)
            || (delta < 0 && expectedNextFrameIndex < this.stopFrameIndex)
          ))
      ) {
        this.stopFrameIndex = undefined;
        this.isAnimating = false;
        return false;

        // Preparing next frame
      } else {
        this.approxFrameIndex += delta;
      }

      const nextFrameIndex = Math.round(this.approxFrameIndex);

      if (!this.getFrame(nextFrameIndex)) {
        this.requestFrame(nextFrameIndex);
        this.isWaiting = true;
        this.isAnimating = false;
        return false;
      }

      return true;
    }, requestMutation);
  }

  private getFrame(frameIndex: number) {
    return this.frames[frameIndex];
  }

  private requestFrame(frameIndex: number) {
    this.frames[frameIndex] = WAITING;

    requestMediaWorker({
      name: 'rlottie:renderFrames',
      args: [this.renderId, frameIndex, this.onFrameLoad.bind(this)],
    }, this.workerIndex);
  }

  private cleanupPrevFrame(frameIndex: number) {
    if (this.framesCount! < 3) {
      return;
    }

    const prevFrameIndex = cycleRestrict(this.framesCount!, frameIndex - 1);
    const prevFrame = this.frames[prevFrameIndex];
    if (isBitmap(prevFrame)) {
      discountCachedFrame(prevFrame);
      prevFrame.close();
    }
    this.frames[prevFrameIndex] = undefined;
  }

  // Keeps only the frames within `BOUNDED_CACHE_WINDOW` ahead of the playhead (plus the currently drawn one)
  private trimFrameCache(currentFrameIndex: number) {
    const framesCount = this.framesCount!;
    if (framesCount <= BOUNDED_CACHE_WINDOW) {
      return;
    }

    for (let i = 0; i < this.frames.length; i++) {
      const frame = this.frames[i];
      if (i === this.prevFrameIndex) {
        continue;
      }

      const distance = cycleRestrict(framesCount, (i - currentFrameIndex) * this.direction);
      if (distance >= BOUNDED_CACHE_WINDOW) {
        if (isBitmap(frame)) {
          discountCachedFrame(frame);
          frame.close();
        }
        if (frame === CONSUMED || isBitmap(frame)) {
          this.frames[i] = undefined;
        }
      }
    }
  }

  private onFrameLoad(frameIndex: number, imageBitmap: ImageBitmap) {
    // The instance was destroyed or the slot was released while the frame was being rendered
    if (this.frames[frameIndex] !== WAITING) {
      imageBitmap.close();
      return;
    }

    this.frames[frameIndex] = imageBitmap;
    countCachedFrame(imageBitmap);

    if (!this.isCacheBounded && frameStats.bytes > FRAME_CACHE_GLOBAL_BUDGET_BYTES) {
      this.isCacheBounded = true;
      this.trimFrameCache(frameIndex);
    }

    if (this.isWaiting) {
      this.doPlay();
    }
  }
}

function ensureCanvasSize(canvas: HTMLCanvasElement, sizeFactor: number) {
  const expectedWidth = Math.round(canvas.offsetWidth * sizeFactor);
  const expectedHeight = Math.round(canvas.offsetHeight * sizeFactor);

  if (canvas.width !== expectedWidth || canvas.height !== expectedHeight) {
    const deferred = new Deferred<void>();
    PENDING_CANVAS_RESIZES.set(canvas, deferred.promise);
    requestMutation(() => {
      canvas.width = expectedWidth;
      canvas.height = expectedHeight;
      deferred.resolve();
    });
  }

  return [expectedWidth, expectedHeight];
}

export default RLottie;
